import{c as d,Z as t,Q as l,j as h,g as o,n as s,o as a,m as n,av as u}from"./chunks/framework.BPKcPtvA.js";const _=JSON.parse(`{"title":"Set the agent's autonomy tier","description":"Choose how much rope the agent gets — from read-only Advisory to autonomous Scoped.","frontmatter":{"title":"Set the agent's autonomy tier","description":"Choose how much rope the agent gets — from read-only Advisory to autonomous Scoped."},"headers":[],"relativePath":"guide/agent/set-tier.md","filePath":"guide/agent/set-tier.md","lastUpdated":1780205082000}`),c={name:"guide/agent/set-tier.md"};function g(p,e,m,y,f,k){const r=t("TaskMeta"),i=t("ExpectedResult");return l(),h("div",null,[e[1]||(e[1]=o("h1",{id:"set-the-agent-s-autonomy-tier",tabindex:"-1"},[s("Set the agent's autonomy tier "),o("a",{class:"header-anchor",href:"#set-the-agent-s-autonomy-tier","aria-label":`Permalink to "Set the agent's autonomy tier"`},"​")],-1)),a(r,{time:"~3 min",role:"Any signed-in user",needs:"Signed in with your passkey"}),e[2]||(e[2]=n('<blockquote><p><strong>What you&#39;ll do:</strong> Pick an autonomy tier for the agent — and learn how choosing <strong>Scoped</strong> mints a session key entirely on your device.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Prerequisites</p><p>Be signed in with your passkey. You decide how much rope the agent gets, and you can change it anytime.</p></div><h2 id="the-four-tiers" tabindex="-1">The four tiers <a class="header-anchor" href="#the-four-tiers" aria-label="Permalink to &quot;The four tiers&quot;">​</a></h2><ul><li><strong>Advisory</strong> — read-only. Every write needs a fresh passkey signature.</li><li><strong>Confirm per action</strong> — the agent proposes; you confirm each write.</li><li><strong>Policy-bound</strong> — the agent writes within an allowlist plus spend caps.</li><li><strong>Scoped autonomy</strong> — autonomous execution with a Scoped session: buys/sells within a per-action ceiling and a time limit, with no per-trade prompt.</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Go to <code>/agent/policy/transition</code> (the dashboard tier picker; you can also ask HavenBot to <em>&quot;open my agent settings&quot;</em>).</li><li><strong>Pick any tier directly</strong> — there&#39;s no ladder to climb and no step-up/step-down sequence. Select the tier you want.</li><li>Your <strong>passkey confirms the change</strong>.</li><li>If you choose <strong>Scoped</strong>, a <strong>session-key reveal modal</strong> opens and mints a short-lived ephemeral key.</li></ol><p>::: important The autonomy tier is set on the dashboard only You set your tier here, on the dashboard — it can&#39;t be changed from MCP. Your own LLM (MCP) acts <em>within</em> the Scoped session you grant here; it doesn&#39;t pick the tier. :::</p><p>::: important The Scoped key is minted on your device The ephemeral session key is generated <strong>client-side</strong> and is <strong>never sent over the wire</strong>. The agent gets time-boxed, capped signing rights — not your passkey. :::</p><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',10)),a(i,null,{default:u(()=>[...e[0]||(e[0]=[s(" The active tier updates as soon as your passkey confirms the change — there's no step-up/step-down ladder. Choosing Scoped leaves you with a freshly minted, time-limited session key. ",-1)])]),_:1}),e[3]||(e[3]=n('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>Scoped modal didn&#39;t mint a key</td><td>Cancel and reopen the modal; the key is generated locally, so retry on-device.</td></tr><tr><td>Want to lock the agent down fast</td><td>Pick <strong>Paused</strong> — it blocks every write instantly (the kill-switch).</td></tr><tr><td>Want to resume after pausing</td><td>Pick any tier again; your passkey installs a fresh session key.</td></tr></tbody></table><p>→ Next: <a href="/guide/agent/autonomous">Let the agent act autonomously</a></p>',3))])}const w=d(c,[["render",g]]);export{_ as __pageData,w as default};
